/*
   Global design system and layout
   Matches clean corporate style with light, optimistic feel.
*/

:root {
    /* Brand palette */
    --color-primary-500: #25B9E6; /* top bar + key accents */
    --color-primary-900: #111111; /* strong text */

    --color-secondary-orange: #F36B2C;
    --color-secondary-yellow: #FFC933;
    --color-secondary-green: #64B847;
    --color-secondary-teal: #00A79D;
    --color-secondary-blue: #246BB4;

    --color-accent: #25B9E6;

    --color-neutral-0: #FFFFFF;
    --color-neutral-50: #F8F8F8;
    --color-neutral-900: #222222;
    --color-border-subtle: #E0E0E0;

    /* Semantic */
    --color-success: #2E7D32;
    --color-error: #C62828;
    --color-warning: #FF9800;
    --color-info: #1976D2;

    /* Typography */
    --font-heading: 'Space Grotesk', 'Helvetica', sans-serif;
    --font-body: 'Source Sans 3', 'Arial', sans-serif;
    --font-code: 'Source Code Pro', monospace;

    --font-size-h1: 32px;
    --font-size-h2: 26px;
    --font-size-h3: 20px;
    --font-size-body: 16px;
    --font-size-small: 14px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (8px base) */
    --space-0-5: 4px;
    --space-1: 8px;
    --space-2: 16px;
    --space-3: 24px;
    --space-4: 32px;
    --space-5: 48px;
    --space-6: 64px;

    --radius-small: 4px;
    --radius-medium: 6px;

    --shadow-subtle: 0 0 0 1px rgba(0, 0, 0, 0.02);

    --max-width-container: 1160px;
}

/* Reset / base */

* {
    box-sizing: border-box;
}

html {
    -webkit-text-size-adjust: 100%;
}

body {
    margin: 0;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-900);
    background-color: var(--color-neutral-0);
}

img {
    max-width: 100%;
    height: auto;
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover,
a:focus-visible {
    text-decoration: underline;
}

ul,
ol {
    margin: 0;
    padding: 0;
}

li {
    list-style: none;
}

h1,
h2,
h3,
h4,
h5,
h6 {
    margin: 0;
    font-family: var(--font-heading);
    font-weight: var(--font-weight-bold);
    color: var(--color-primary-900);
}

p {
    margin: 0;
}

.container {
    max-width: var(--max-width-container);
    margin: 0 auto;
    padding: 0 var(--space-3);
}

/* Header */

.site-header {
    position: relative;
    width: 100%;
    background-color: var(--color-neutral-0);
}

/* Top utility bar */

.top-utility-bar {
    background-color: var(--color-primary-500);
    color: var(--color-primary-900);
    font-family: var(--font-body);
    font-size: var(--font-size-small);
}

.utility-content {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 40px;
}

.utility-left,
.utility-center,
.utility-right {
    display: flex;
    align-items: center;
    gap: var(--space-1);
}

.utility-center {
    justify-content: center;
    flex: 1 1 auto;
}

.utility-left,
.utility-right {
    flex: 0 0 auto;
}

.utility-text {
    letter-spacing: 0.03em;
}

.utility-icon {
    font-size: 14px;
}

.utility-follow-label {
    font-weight: var(--font-weight-semibold);
    text-transform: uppercase;
    letter-spacing: 0.08em;
}

.social-icon {
    font-weight: var(--font-weight-semibold);
    font-family: var(--font-heading);
    font-size: 13px;
}

/* Main header bar */

.main-header-bar {
    background-color: var(--color-neutral-0);
    border-bottom: 1px solid var(--color-border-subtle);
}

.main-header-content {
    display: flex;
    align-items: center;
    justify-content: space-between;
    min-height: 72px;
    gap: var(--space-3);
}

/* Brand / logo */

.brand {
    display: flex;
    align-items: flex-end;
    gap: var(--space-0-5);
    text-decoration: none;
    padding: var(--space-1) 0;
}

.brand-mark {
    display: inline-flex;
    align-items: baseline;
    font-family: var(--font-heading);
    font-weight: var(--font-weight-bold);
    font-size: 30px;
    letter-spacing: 0.03em;
}

.brand-letter {
    display: inline-block;
}

.brand-letter-f { color: var(--color-secondary-orange); }
.brand-letter-o { color: var(--color-secondary-yellow); }
.brand-letter-c { color: var(--color-secondary-green); }
.brand-letter-u { color: var(--color-secondary-teal); }
.brand-letter-s { color: var(--color-secondary-blue); }

.brand-subtitle {
    font-family: var(--font-heading);
    font-size: 12px;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    color: var(--color-primary-900);
    margin-bottom: 4px;
}

/* Primary navigation */

.primary-nav {
    flex: 1 1 auto;
}

.primary-nav-list {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: var(--space-3);
}

.primary-nav-item {
    position: relative;
}

.primary-nav-link {
    display: inline-block;
    padding: 24px 0 18px;
    font-family: var(--font-heading);
    font-size: 13px;
    font-weight: var(--font-weight-medium);
    text-transform: uppercase;
    letter-spacing: 0.14em;
    color: var(--color-primary-900);
    border-bottom: 2px solid transparent;
}

.primary-nav-link:hover,
.primary-nav-link:focus-visible {
    text-decoration: none;
    color: var(--color-accent);
    border-bottom-color: var(--color-accent);
}

.primary-nav-link.is-active {
    color: var(--color-accent);
    border-bottom-color: var(--color-accent);
}

/* Language indicator */

.header-language {
    display: inline-flex;
    align-items: center;
    gap: var(--space-0-5);
    border: 1px solid var(--color-accent);
    padding: 6px 10px;
    border-radius: var(--radius-small);
    font-family: var(--font-heading);
    font-size: 12px;
    font-weight: var(--font-weight-medium);
    text-transform: uppercase;
    letter-spacing: 0.12em;
    color: var(--color-primary-900);
}

.language-flag {
    width: 14px;
    height: 10px;
    border-radius: 2px;
    box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.08);
    background: linear-gradient(180deg, #ffffff 0%, #ffffff 33%, #246BB4 33%, #246BB4 66%, #ffffff 66%, #ffffff 100%);
}

.language-code {
    display: inline-block;
}

/* Main content area */

.site-content {
    padding: var(--space-5) var(--space-3) var(--space-6);
}

@media (min-width: 768px) {
    .site-content {
        padding-top: var(--space-6);
        padding-bottom: var(--space-6);
    }
}

/* Footer */

.site-footer {
    border-top: 1px solid var(--color-border-subtle);
    background-color: var(--color-neutral-0);
}

.footer-main {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-4);
    padding-top: var(--space-5);
    padding-bottom: var(--space-4);
}

.footer-brand {
    flex: 1 1 260px;
}

.footer-logo {
    display: flex;
    align-items: flex-end;
    gap: var(--space-0-5);
    margin-bottom: var(--space-2);
}

.footer-tagline {
    max-width: 420px;
    font-size: var(--font-size-small);
    line-height: var(--line-height-relaxed);
    color: #555555;
}

.footer-links-columns {
    display: flex;
    flex: 2 1 320px;
    gap: var(--space-4);
}

.footer-column {
    min-width: 140px;
}

.footer-heading {
    font-family: var(--font-heading);
    font-size: 13px;
    text-transform: uppercase;
    letter-spacing: 0.14em;
    margin-bottom: var(--space-2);
}

.footer-links-list li + li {
    margin-top: var(--space-1);
}

.footer-links-list a {
    font-size: var(--font-size-small);
    color: var(--color-neutral-900);
}

.footer-links-list a:hover,
.footer-links-list a:focus-visible {
    color: var(--color-accent);
    text-decoration: none;
}

.footer-bottom {
    border-top: 1px solid var(--color-border-subtle);
    background-color: var(--color-neutral-50);
}

.footer-bottom-content {
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
}

.footer-copy {
    font-size: 12px;
    color: #777777;
}

/* Responsive adjustments */

@media (max-width: 900px) {
    .utility-content {
        flex-wrap: wrap;
        justify-content: center;
        row-gap: var(--space-1);
        height: auto;
        padding-top: var(--space-1);
        padding-bottom: var(--space-1);
    }

    .main-header-content {
        flex-wrap: wrap;
        justify-content: center;
        padding-top: var(--space-1);
        padding-bottom: var(--space-1);
    }

    .header-language {
        order: -1;
    }
}

@media (max-width: 640px) {
    .primary-nav-list {
        gap: var(--space-2);
        justify-content: flex-start;
    }

    .primary-nav-link {
        padding-top: 16px;
        padding-bottom: 10px;
        font-size: 12px;
    }

    .site-content {
        padding-top: var(--space-4);
        padding-bottom: var(--space-4);
    }

    .footer-main {
        padding-top: var(--space-4);
        padding-bottom: var(--space-3);
    }
}
